// Helper: Write big-endian 32-bit integer (for pack file writing)
static void write_be32_pack(uint8_t* ptr, uint32_t value) {
    ptr[0] = static_cast<uint8_t>(value >> 24);
    ptr[1] = static_cast<uint8_t>(value >> 16);
    ptr[2] = static_cast<uint8_t>(value >> 8);
    ptr[3] = static_cast<uint8_t>(value);
}

// Write pack file variable-length encoding
// First byte: (type << 4) | (size & 0x0F) | (continuation ? 0x80 : 0)
// Subsequent bytes: (size & 0x7F) | (continuation ? 0x80 : 0)
static size_t write_pack_varint(uint8_t* buffer, int type, uint64_t size) {
    uint8_t* p = buffer;

    // First byte: continuation bit + type (3 bits) + size (4 bits)
    *p = static_cast<uint8_t>((type << 4) | (size & 0x0F));
    size >>= 4;

    if (size > 0) {
        *p |= 0x80;  // Set continuation bit
        p++;

        while (size > 0) {
            *p = static_cast<uint8_t>(size & 0x7F);
            size >>= 7;
            if (size > 0) *p |= 0x80;
            p++;
        }
    } else {
        p++;
    }

    return p - buffer;
}

// Read a git object and return its raw content (without header)
// Returns allocated buffer (caller must delete[]), fills out_size
static char* read_object_content(GitRepository* repo, const char* sha,
                                  int* out_type, size_t* out_size) {
    if (!repo || !sha) return nullptr;

    // Try loose object first
    char* data = nullptr;
    GitObjectType type;
    size_t size = read_loose_object(repo, sha, &data, &type);

    if (size > 0 && data) {
        *out_type = static_cast<int>(type);
        *out_size = size;
        return data;
    }

    // Try pack files
    int pack_type;
    data = read_pack_object_by_sha(repo, sha, &pack_type, &size);
    if (data && size > 0) {
        *out_type = pack_type;
        *out_size = size;
        return data;
    }

    return nullptr;
}

// Write a pack file containing the specified objects (non-delta encoding)
// Returns allocated buffer (caller must delete[]), fills out_size
// Returns nullptr on failure
char* git_write_pack(GitRepository* repo, ObjectToSend* objects, size_t object_count,
                     size_t* out_size, PushProgress* progress) {
    if (!repo || !objects || object_count == 0 || !out_size) {
        return nullptr;
    }

    if (object_count > UINT32_MAX) {
        LOG_ERROR("git_write_pack: object_count exceeds uint32_t");
        return nullptr;
    }

    // Estimate max pack size: header(12) + objects + checksum(20)
    // Each object: max_varint(10) + compressed_data
    // Start with reasonable buffer, grow if needed
    size_t buffer_capacity = 12 + 20 + object_count * 1024;  // Initial estimate
    uint8_t* buffer = new uint8_t[buffer_capacity];

    // Write pack header: "PACK" + version(4) + object_count(4)
    memcpy(buffer, "PACK", 4);
    write_be32_pack(buffer + 4, 2);  // Version 2
    write_be32_pack(buffer + 8, static_cast<uint32_t>(object_count));

    size_t offset = 12;  // After header

    // Temporary buffer for compression
    size_t compress_capacity = 1024 * 1024;  // 1MB initial
    uint8_t* compress_buffer = new uint8_t[compress_capacity];

    for (size_t i = 0; i < object_count; i++) {
        if (progress) {
            progress->objects_done.store(i);
            progress->objects_total.store(object_count);
            if (progress->base.cancel_requested.load()) {
                delete[] buffer;
                delete[] compress_buffer;
                return nullptr;
            }
        }

        // Read object content
        int obj_type;
        size_t obj_size;
        char* obj_data = read_object_content(repo, objects[i].sha, &obj_type, &obj_size);

        if (!obj_data) {
            delete[] buffer;
            delete[] compress_buffer;
            return nullptr;
        }

        // Ensure compress buffer is large enough
        size_t max_compressed = obj_size + (obj_size / 1000) + 12 + 256;
        if (max_compressed > compress_capacity) {
            delete[] compress_buffer;
            compress_capacity = max_compressed * 2;
            compress_buffer = new uint8_t[compress_capacity];
        }

        // Compress object content
        size_t compressed_size = zlib_compress(obj_data, obj_size,
                                                compress_buffer, compress_capacity);
        delete[] obj_data;

        if (compressed_size == 0) {
            delete[] buffer;
            delete[] compress_buffer;
            return nullptr;
        }

        // Calculate space needed for this entry
        uint8_t varint_buf[16];
        size_t varint_len = write_pack_varint(varint_buf, obj_type, obj_size);
        size_t entry_size = varint_len + compressed_size;

        // Grow buffer if needed
        while (offset + entry_size + 20 > buffer_capacity) {
            size_t new_capacity = buffer_capacity * 2;
            uint8_t* new_buffer = new uint8_t[new_capacity];
            memcpy(new_buffer, buffer, offset);
            delete[] buffer;
            buffer = new_buffer;
            buffer_capacity = new_capacity;
        }

        // Write varint (type + size)
        memcpy(buffer + offset, varint_buf, varint_len);
        offset += varint_len;

        // Write compressed data
        memcpy(buffer + offset, compress_buffer, compressed_size);
        offset += compressed_size;

        // Update progress bytes
        if (progress) {
            progress->bytes_sent.store(offset);
        }
    }

    delete[] compress_buffer;

    // Compute and append SHA-1 checksum of entire pack (excluding checksum itself)
    uint8_t pack_sha[20];
    sha1_compute(buffer, offset, pack_sha);
    memcpy(buffer + offset, pack_sha, 20);
    offset += 20;

    if (progress) {
        progress->objects_done.store(object_count);
    }

    *out_size = offset;
    return reinterpret_cast<char*>(buffer);
}

