// Hash set for tracking visited SHAs during object collection
struct ShaHashSet {
    char (*buckets)[Git::SHA1_HEX_SIZE + 1];
    bool* used;
    size_t bucket_count;
    size_t count;

    void init(size_t expected_count = 16384) {
        bucket_count = 1;
        while (bucket_count < expected_count * 2) bucket_count <<= 1;
        buckets = new (std::nothrow) char[bucket_count][Git::SHA1_HEX_SIZE + 1];
        used = new (std::nothrow) bool[bucket_count];
        if (!buckets || !used) {
            delete[] buckets;
            delete[] used;
            buckets = nullptr;
            used = nullptr;
            bucket_count = 0;
            count = 0;
            return;
        }
        memset(used, 0, bucket_count * sizeof(bool));
        count = 0;
    }

    ~ShaHashSet() {
        delete[] buckets;
        delete[] used;
    }

    uint32_t hash(const char* sha) const {
        // Simple hash from first 8 hex chars
        uint32_t h = 0;
        for (int i = 0; i < 8 && sha[i]; i++) {
            h = h * 31 + static_cast<uint8_t>(sha[i]);
        }
        return bucket_count ? (h & static_cast<uint32_t>(bucket_count - 1)) : 0;
    }

    bool contains(const char* sha) const {
        if (!sha || !used || bucket_count == 0) return false;
        uint32_t idx = hash(sha);
        for (size_t probe = 0; probe < bucket_count; probe++) {
            size_t i = (idx + probe) & (bucket_count - 1);
            if (!used[i]) return false;
            if (strcmp(buckets[i], sha) == 0) return true;
        }
        return false;
    }

    bool grow() {
        size_t old_bucket_count = bucket_count;
        char (*old_buckets)[Git::SHA1_HEX_SIZE + 1] = buckets;
        bool* old_used = used;

        bucket_count *= 2;
        buckets = new (std::nothrow) char[bucket_count][Git::SHA1_HEX_SIZE + 1];
        used = new (std::nothrow) bool[bucket_count];
        if (!buckets || !used) {
            delete[] buckets;
            delete[] used;
            buckets = old_buckets;
            used = old_used;
            bucket_count = old_bucket_count;
            return false;
        }
        memset(used, 0, bucket_count * sizeof(bool));
        count = 0;

        for (size_t i = 0; i < old_bucket_count; i++) {
            if (old_used[i]) insert(old_buckets[i]);
        }

        delete[] old_buckets;
        delete[] old_used;
        return true;
    }

    bool insert(const char* sha) {
        if (contains(sha)) return false;
        if (!sha || !used || bucket_count == 0) return false;
        if ((count + 1) * 4 >= bucket_count * 3) {
            if (!grow()) return false;
        }

        uint32_t idx = hash(sha);
        for (size_t probe = 0; probe < bucket_count; probe++) {
            size_t i = (idx + probe) & (bucket_count - 1);
            if (!used[i]) {
                strcpy_s(buckets[i], sha);
                used[i] = true;
                count++;
                return true;
            }
        }
        return false;
    }
};

// Forward declaration for recursive tree collection
// out_truncated: set true if the tree walk stopped because max_objects was full
// while entries remained (incomplete pack risk).
static size_t collect_tree_objects_recursive(GitRepository* repo, const char* tree_sha,
                                              ObjectToSend* objects, size_t current_count,
                                              size_t max_objects, ShaHashSet* visited,
                                              bool* out_truncated);

// Recursively collect all objects in a tree (trees and blobs)
static size_t collect_tree_objects_recursive(GitRepository* repo, const char* tree_sha,
                                              ObjectToSend* objects, size_t current_count,
                                              size_t max_objects, ShaHashSet* visited,
                                              bool* out_truncated) {
    if (current_count >= max_objects) {
        // Caller still needed this tree but buffer is full
        if (out_truncated) *out_truncated = true;
        return current_count;
    }
    if (visited->contains(tree_sha)) return current_count;

    // Add tree object
    visited->insert(tree_sha);
    strcpy_s(objects[current_count].sha, tree_sha);
    objects[current_count].type = Git::OBJ_TREE;
    objects[current_count].size = 0;  // Will be filled when writing pack
    current_count++;

    // Read tree entries - use heap to avoid stack overflow (4096 * ~300 bytes = 1.2MB!)
    GitTreeEntry* entries = new GitTreeEntry[Git::MAX_TREE_ENTRIES];
    size_t entry_count = git_read_tree(repo, tree_sha, entries, Git::MAX_TREE_ENTRIES);

    for (size_t i = 0; i < entry_count; i++) {
        if (visited->contains(entries[i].sha)) continue;

        // Skip gitlinks (submodule references) - they point to commits in external repos
        if (entries[i].mode == Git::MODE_GITLINK) {
            continue;
        }

        // Need a free slot for the next blob/subtree root
        if (current_count >= max_objects) {
            if (out_truncated) *out_truncated = true;
            break;
        }

        if (entries[i].mode == Git::MODE_TREE) {
            // Recursively collect subtree
            current_count = collect_tree_objects_recursive(repo, entries[i].sha,
                                                           objects, current_count,
                                                           max_objects, visited,
                                                           out_truncated);
            if (out_truncated && *out_truncated) break;
        } else {
            // Add blob
            visited->insert(entries[i].sha);
            strcpy_s(objects[current_count].sha, entries[i].sha);
            objects[current_count].type = Git::OBJ_BLOB;
            objects[current_count].size = 0;
            current_count++;
        }
    }

    delete[] entries;
    return current_count;
}

// Collect all objects needed for push (commits, trees, blobs)
// Walks from local_sha backwards until reaching remote_sha (or root)
// Returns number of objects collected (0..max_objects on success).
// Returns max_objects+1 if the set would exceed max_objects (incomplete pack risk).
// Exact fit of max_objects is success when the walk finishes completely.
size_t git_collect_push_objects(GitRepository* repo, const char* local_sha,
                                 const char* remote_sha, ObjectToSend* objects,
                                 size_t max_objects) {
    if (!repo || !repo->is_valid || !local_sha || !objects || max_objects == 0) {
        return 0;
    }

    ShaHashSet* visited = new ShaHashSet();
    visited->init();
    ShaHashSet* server_has = new ShaHashSet();
    server_has->init();

    // If remote_sha provided, mark its full ancestry as already present on the server.
    if (remote_sha && remote_sha[0]) {
        struct QueueEntry { char sha[Git::SHA1_HEX_SIZE + 1]; };
        size_t queue_capacity = 1024;
        QueueEntry* queue = new (std::nothrow) QueueEntry[queue_capacity];
        size_t head = 0, tail = 0;
        if (queue) {
            strcpy_s(queue[tail++].sha, remote_sha);
            while (head < tail) {
                char current[Git::SHA1_HEX_SIZE + 1];
                strcpy_s(current, queue[head++].sha);
                if (server_has->contains(current)) continue;
                server_has->insert(current);

                GitCommit commit = {};
                if (!git_read_commit(repo, current, &commit)) continue;

                const char* parents[2] = { commit.parent_sha, commit.parent2_sha };
                for (int p = 0; p < 2; p++) {
                    if (!parents[p][0] || server_has->contains(parents[p])) continue;
                    if (tail >= queue_capacity) {
                        size_t new_capacity = queue_capacity * 2;
                        QueueEntry* grown = new (std::nothrow) QueueEntry[new_capacity];
                        if (!grown) continue;
                        memcpy(grown, queue, queue_capacity * sizeof(QueueEntry));
                        delete[] queue;
                        queue = grown;
                        queue_capacity = new_capacity;
                    }
                    strcpy_s(queue[tail++].sha, parents[p]);
                }
            }
            delete[] queue;
        } else {
            server_has->insert(remote_sha);
        }
    }

    size_t count = 0;
    struct QueueEntry { char sha[Git::SHA1_HEX_SIZE + 1]; };
    size_t queue_capacity = 1024;
    QueueEntry* queue = new (std::nothrow) QueueEntry[queue_capacity];
    size_t head = 0, tail = 0;
    if (!queue) {
        delete server_has;
        delete visited;
        return 0;
    }
    strcpy_s(queue[tail++].sha, local_sha);

    bool hit_object_limit = false;
    while (head < tail) {
        // Need a free slot for the next commit. count == max_objects with more
        // queue work is overflow; count == max_objects with empty queue is OK
        // (exact fit) — checked after the loop via head < tail.
        if (count >= max_objects) {
            hit_object_limit = true;
            break;
        }

        char current_sha[Git::SHA1_HEX_SIZE + 1];
        strcpy_s(current_sha, queue[head++].sha);

        if (server_has->contains(current_sha) || visited->contains(current_sha)) continue;

        // Read commit
        GitCommit commit = {};
        if (!git_read_commit(repo, current_sha, &commit)) {
            continue;
        }

        // Add commit object
        visited->insert(current_sha);
        strcpy_s(objects[count].sha, current_sha);
        objects[count].type = Git::OBJ_COMMIT;
        objects[count].size = 0;
        count++;

        // Collect tree objects for this commit (may fill remaining slots up to max)
        if (commit.tree_sha[0]) {
            bool tree_truncated = false;
            count = collect_tree_objects_recursive(repo, commit.tree_sha,
                                                    objects, count, max_objects, visited,
                                                    &tree_truncated);
            if (tree_truncated) {
                // Mid-tree stop: incomplete even if count == max_objects exactly
                hit_object_limit = true;
                break;
            }
        }

        const char* parents[2] = { commit.parent_sha, commit.parent2_sha };
        for (int p = 0; p < 2; p++) {
            if (!parents[p][0] || server_has->contains(parents[p]) || visited->contains(parents[p])) continue;
            if (tail >= queue_capacity) {
                size_t new_capacity = queue_capacity * 2;
                QueueEntry* grown = new (std::nothrow) QueueEntry[new_capacity];
                if (!grown) continue;
                memcpy(grown, queue, queue_capacity * sizeof(QueueEntry));
                delete[] queue;
                queue = grown;
                queue_capacity = new_capacity;
            }
            strcpy_s(queue[tail++].sha, parents[p]);
        }
    }

    // Truncation: either mid-walk limit hit, or queue still has unprocessed tips.
    // Exact max_objects with fully drained queue is success (not overflow).
    if (hit_object_limit || head < tail) {
        delete[] queue;
        delete server_has;
        delete visited;
        return max_objects + 1;
    }

    delete[] queue;
    delete server_has;
    delete visited;
    return count;
}
